                style={{
                  position: 'relative',
                  width: '100%', display: 'flex', alignItems: 'center', gap: '0.75rem',
                  padding: '0.75rem 1rem', background: idx === selectedIndex ? 'rgba(255, 255, 255, 0.05)' : 'transparent', border: 'none',
