                {/* Card Header */}
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0.7rem 1rem', borderBottom: '1px solid var(--border-subtle)', background: isDoneForToday ? 'rgba(16,185,129,0.05)' : 'rgba(0,0,0,0.1)' }}>
