                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.45rem' }}>
                    {isDoneForToday && (
                      <span style={{ fontSize: '0.67rem', fontWeight: 700, background: 'rgba(16,185,129,0.15)', color: '#10b981', padding: '0.12rem 0.45rem', borderRadius: '5px', border: '1px solid rgba(16,185,129,0.3)' }}>Γ£ô Done today</span>
                    )}
                    <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Target: {target}%</span>
