interface EventPopoverProps {
  x: number;
  y: number;
  initialDate: string;
  initialStartTime: string;
  initialEndTime: string;
  onClose: () => void;
  onSave: (data: {
    title: string;
    type: string;
    date: string;
    startTime: string;
    endTime: string;
    guests: string[];
    meetLink: string;
    location: string;
    description: string;
  }) => void;
  existingEvent?: any;
  onDelete?: (id: string) => void;
}

