                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              {/* Quick Prompts ΓÇö sticky at bottom of chat */}
              <div style={{ flexShrink: 0, padding: '0 1rem 0.3rem', borderTop: '1px solid rgba(255,255,255,0.05)' }}>
