            placeholder={todayLog ? `Today: ${todayLog.weightKg}kg (update)` : 'Enter today\'s weight (kg)'}
            style={{
              width: '100%', padding: '0.6rem 0.8rem', borderRadius: '10px',
              background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.12)',
