      ) : loading ? (
        <div style={{ textAlign: 'center', padding: '1rem', color: 'rgba(255,255,255,0.3)', fontSize: '0.78rem' }}>LoadingΓÇª</div>
      ) : (
        <div style={{ textAlign: 'center', padding: '1rem 0.5rem', color: 'rgba(255,255,255,0.3)', fontSize: '0.78rem' }}>
