import React, { useState, useEffect } from 'react';
import { Sparkles, TrendingUp, Lightbulb, Plus, Loader2, RefreshCw, AlertCircle } from 'lucide-react';
import { generateAnalyticsInsights } from '../../services/gemini';
import { addDoc, collection } from 'firebase/firestore';
import { db, auth } from '../../services/firebase';
import { toast } from 'sonner';

interface AIInsightsPanelProps {
  userData: any;
}

const CACHE_KEY = 'zen_ai_insights_cache';

const loadCache = () => {
  try {
    const raw = sessionStorage.getItem(CACHE_KEY);
    if (!raw) return null;
    const { data, ts } = JSON.parse(raw);
    // Cache valid for 30 minutes
    if (Date.now() - ts < 30 * 60 * 1000) return data;
    sessionStorage.removeItem(CACHE_KEY);
    return null;
  } catch { return null; }
};

const saveCache = (data: any) => {
  try {
    sessionStorage.setItem(CACHE_KEY, JSON.stringify({ data, ts: Date.now() }));
  } catch { /* ignore */ }
};

export const AIInsightsPanel: React.FC<AIInsightsPanelProps> = ({ userData }) => {
  const [loading, setLoading] = useState(false);
  const [data, setData] = useState<{ insights: string[]; recommendations: any[] } | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Load cached insights on mount
  useEffect(() => {
    const cached = loadCache();
    if (cached) setData(cached);
  }, []);

  const generate = async (force = false) => {
    if (!force) {
      const cached = loadCache();
      if (cached) { setData(cached); return; }
    }

    setLoading(true);
    setError(null);
    try {
      const result = await generateAnalyticsInsights(userData);

      // Validate response structure
      if (!result || !Array.isArray(result.insights) || !Array.isArray(result.recommendations)) {
        throw new Error('AI returned an unexpected format. Please try again.');
      }

      setData(result);
      saveCache(result);
    } catch (err: any) {
      const msg = err.message || 'Failed to generate insights';
      setError(msg);
      toast.error(msg.includes('quota') ? 'AI quota reached. Try again in a few minutes.' : `AI Error: ${msg}`);
    }
    setLoading(false);
  };

  const addRecommendedTask = async (task: any) => {
    const user = auth.currentUser;
    if (!user) return toast.error('You must be logged in.');
    try {
      const todayStr = new Date().toLocaleDateString('en-CA');
      await addDoc(collection(db, 'todos'), {
        userId: user.uid,
        title: task.title,
        priority: task.priority || 'medium',
        estimatedMinutes: task.estimatedMinutes || 25,
        status: 'pending',
        date: todayStr,
        createdAt: Date.now(),
      });
      toast.success(`Task "${task.title}" added to today!`);
    } catch {
      toast.error('Failed to add task. Please try again.');
    }
  };

  return (
    <div className="topic-card" style={{ padding: '1.5rem', gridColumn: '1 / -1', position: 'relative', overflow: 'hidden' }}>
      <div style={{ position: 'absolute', inset: 0, border: '2px solid transparent', borderRadius: 'inherit', background: 'linear-gradient(45deg, rgba(168,85,247,0.3), rgba(16,185,129,0.3)) border-box', WebkitMask: 'linear-gradient(#fff 0 0) padding-box, linear-gradient(#fff 0 0)', WebkitMaskComposite: 'xor', maskComposite: 'exclude', pointerEvents: 'none' }} />

      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
        <h3 style={{ fontSize: '1.1rem', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '0.5rem', color: 'var(--text-primary)' }}>
          <Sparkles size={20} style={{ color: '#a855f7' }} /> Zen AI Insights
          {data && <span style={{ fontSize: '0.7rem', color: 'var(--text-muted)', fontWeight: 400, marginLeft: '0.5rem' }}>Cached ┬╖ updates every 30 min</span>}
        </h3>
        <div style={{ display: 'flex', gap: '0.5rem' }}>
          {data && (
            <button
              className="btn-secondary"
              onClick={() => generate(true)}
              disabled={loading}
              style={{ padding: '0.5rem 0.75rem', display: 'flex', alignItems: 'center', gap: '0.4rem', fontSize: '0.8rem' }}
              title="Regenerate insights"
            >
              <RefreshCw size={14} className={loading ? 'animate-spin' : ''} /> Refresh
            </button>
          )}
          <button
            className="btn-primary"
            onClick={() => generate(false)}
            disabled={loading}
            style={{ padding: '0.5rem 1rem', display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.85rem' }}
          >
            {loading ? <Loader2 size={16} className="animate-spin" /> : <Sparkles size={16} />}
            {data ? 'View Latest' : 'Generate Insights'}
          </button>
        </div>
      </div>

      {/* Error State */}
      {error && !loading && (
        <div style={{ color: '#ef4444', fontSize: '0.9rem', padding: '1rem', background: 'rgba(239,68,68,0.08)', borderRadius: 'var(--radius-sm)', border: '1px solid rgba(239,68,68,0.2)', display: 'flex', alignItems: 'flex-start', gap: '0.5rem' }}>
          <AlertCircle size={16} style={{ flexShrink: 0, marginTop: '0.1rem' }} />
          <div>
            <span>{error}</span>
            <button
              onClick={() => generate(true)}
              style={{ marginLeft: '0.75rem', color: '#a855f7', textDecoration: 'underline', background: 'none', border: 'none', cursor: 'pointer', fontSize: '0.85rem' }}
            >
              Try Again
            </button>
          </div>
        </div>
      )}

      {/* Empty State */}
      {!data && !loading && !error && (
        <div style={{ textAlign: 'center', padding: '2.5rem 1rem', color: 'var(--text-muted)', fontSize: '0.95rem' }}>
          <Sparkles size={32} style={{ margin: '0 auto 1rem', opacity: 0.3 }} />
          <p>Click <strong>Generate Insights</strong> to analyse your last 30 days and receive personalized AI coaching.</p>
        </div>
      )}

      {/* Loading State */}
      {loading && (
        <div style={{ textAlign: 'center', padding: '2rem 1rem', color: 'var(--text-muted)', fontSize: '0.95rem', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1rem' }}>
          <Loader2 size={28} className="animate-spin" style={{ color: '#a855f7' }} />
          <span>Analyzing your productivity footprint...</span>
        </div>
      )}

      {/* Results */}
      {data && !loading && (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '1.5rem' }}>
          {/* Insights */}
          <div>
            <h4 style={{ fontSize: '0.9rem', fontWeight: 600, color: 'var(--text-secondary)', marginBottom: '0.75rem', display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
              <TrendingUp size={16} /> Key Patterns
            </h4>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
              {(data.insights || []).filter(Boolean).map((insight, i) => (
                <div key={i} style={{ background: 'var(--bg-base)', padding: '1rem', borderRadius: 'var(--radius-sm)', border: '1px solid var(--border-subtle)', fontSize: '0.9rem', lineHeight: 1.5, color: 'var(--text-primary)' }}>
                  {insight}
                </div>
              ))}
            </div>
          </div>

          {/* Recommendations */}
          <div>
            <h4 style={{ fontSize: '0.9rem', fontWeight: 600, color: 'var(--text-secondary)', marginBottom: '0.75rem', display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
              <Lightbulb size={16} /> Recommended Actions
            </h4>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
              {(data.recommendations || []).filter(Boolean).map((rec, i) => (
                <div key={i} style={{ background: 'var(--bg-base)', padding: '1rem', borderRadius: 'var(--radius-sm)', border: '1px solid var(--border-subtle)', display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <span style={{ fontSize: '0.95rem', fontWeight: 600, color: 'var(--text-primary)' }}>{rec.title}</span>
                    {rec.estimatedMinutes && (
                      <span style={{ fontSize: '0.75rem', padding: '0.15rem 0.4rem', borderRadius: '4px', background: 'rgba(168,85,247,0.1)', color: '#a855f7', flexShrink: 0 }}>
                        {rec.estimatedMinutes}m
                      </span>
                    )}
                  </div>
                  {rec.description && (
                    <p style={{ fontSize: '0.85rem', color: 'var(--text-muted)', margin: 0 }}>{rec.description}</p>
                  )}
                  <button
                    className="btn-secondary"
                    onClick={() => addRecommendedTask(rec)}
                    style={{ marginTop: '0.25rem', alignSelf: 'flex-start', padding: '0.35rem 0.75rem', fontSize: '0.8rem', display: 'flex', alignItems: 'center', gap: '0.3rem' }}
                  >
                    <Plus size={14} /> Add to Today
                  </button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { X, Plus, Trash2, GripVertical, CheckCircle2, Play, BookOpen, Loader, Sparkles, ChevronDown, ChevronRight, Save, Clock } from 'lucide-react';
import { DragDropContext, Droppable, Draggable } from '@hello-pangea/dnd';
import { fetchYouTubePlaylist, extractPlaylistId } from '../../services/youtube';

interface SourceVideo {
  id: string; // unique for this list
  videoId: string;
  title: string;
  url: string;
  durationStr?: string; // e.g. "14:20"
}

interface StagedSource {
  id: string;
  title: string;
  type: 'playlist' | 'bulk';
  videos: SourceVideo[];
  isExpanded: boolean;
  searchQuery: string;
  rangeInput: string;
}

interface DraftTopic {
  id: string;
  title: string;
  videos: SourceVideo[];
}

const STORAGE_KEY = 'zentrack_curriculum_draft';

// Helper to parse duration string "1:15:20" into seconds
const parseDuration = (dur: string) => {
  if (!dur) return 0;
  const parts = dur.split(':').map(Number);
  if (parts.length === 3) return parts[0] * 3600 + parts[1] * 60 + parts[2];
  if (parts.length === 2) return parts[0] * 60 + parts[1];
  return parts[0] || 0;
};

// Helper to format seconds into "1h 15m" or "15m"
const formatTotalDuration = (seconds: number) => {
  if (seconds === 0) return '';
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  if (h > 0) return `${h}h ${m}m`;
  return `${m}m`;
};

export const CurriculumBuilderModal = ({ onClose, onPublish }: {
  onClose: () => void;
  onPublish: (topics: DraftTopic[]) => void;
}) => {
  // ΓöÇΓöÇΓöÇ STATE INITIALIZATION (AUTO-SAVE) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const [stagedSources, setStagedSources] = useState<StagedSource[]>(() => {
    try { const saved = localStorage.getItem(STORAGE_KEY + '_sources'); return saved ? JSON.parse(saved) : []; } catch { return []; }
  });
  const [draftTopics, setDraftTopics] = useState<DraftTopic[]>(() => {
    try { const saved = localStorage.getItem(STORAGE_KEY + '_topics'); return saved ? JSON.parse(saved) : []; } catch { return []; }
  });

  const [playlistUrl, setPlaylistUrl] = useState('');
  const [fetchingPlaylist, setFetchingPlaylist] = useState(false);
  const [bulkText, setBulkText] = useState('');
  const [fetchingBulk, setFetchingBulk] = useState(false);
  const [newTopicTitle, setNewTopicTitle] = useState('');
  const [selectedVideoIds, setSelectedVideoIds] = useState<Set<string>>(new Set());
  const [previewVideoId, setPreviewVideoId] = useState<string | null>(null);

  // Sync to local storage
  useEffect(() => { localStorage.setItem(STORAGE_KEY + '_sources', JSON.stringify(stagedSources)); }, [stagedSources]);
  useEffect(() => { localStorage.setItem(STORAGE_KEY + '_topics', JSON.stringify(draftTopics)); }, [draftTopics]);

  useEffect(() => {
    document.body.style.overflow = 'hidden';
    return () => { document.body.style.overflow = 'auto'; };
  }, []);

  const clearWorkspace = () => {
    if (!window.confirm("Are you sure you want to clear your entire workspace? This cannot be undone.")) return;
    setStagedSources([]);
    setDraftTopics([]);
    setSelectedVideoIds(new Set());
    localStorage.removeItem(STORAGE_KEY + '_sources');
    localStorage.removeItem(STORAGE_KEY + '_topics');
  };

  const handlePublishClick = () => {
    onPublish(draftTopics);
    localStorage.removeItem(STORAGE_KEY + '_sources');
    localStorage.removeItem(STORAGE_KEY + '_topics');
  };

  // ΓöÇΓöÇΓöÇ SOURCE FETCHING LOGIC ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const handleFetchPlaylist = async () => {
    if (!playlistUrl.trim()) return;
    const pid = extractPlaylistId(playlistUrl);
    if (!pid) { alert('Invalid Playlist URL'); return; }

    setFetchingPlaylist(true);
    try {
      const data = await fetchYouTubePlaylist(pid);
      const videos: SourceVideo[] = data.videos.map((v: any) => ({
        id: crypto.randomUUID(),
        videoId: v.videoId,
        title: v.title,
        url: v.link,
        durationStr: v.durationStr
      }));

      const newSource: StagedSource = {
        id: crypto.randomUUID(),
        title: data.title,
        type: 'playlist',
        videos,
        isExpanded: true,
        searchQuery: '',
        rangeInput: ''
      };

      setStagedSources(prev => [newSource, ...prev]);
      setPlaylistUrl('');

      // Auto-select the newly added videos
      const newSelected = new Set(selectedVideoIds);
      videos.forEach(v => newSelected.add(v.id));
      setSelectedVideoIds(newSelected);

    } catch (err: any) { alert(err.message || 'Failed to fetch playlist'); } 
    finally { setFetchingPlaylist(false); }
  };

  const extractYoutubeIdBulk = (url: string) => {
    if (!url) return null;
    const match = url.match(/(?:youtu\.be\/|youtube\.com\/(?:embed\/|v\/|watch\?v=|watch\?.+&v=))([^&?]+)/);
    return match ? match[1] : null;
  };

  const handleBulkImport = async () => {
    if (!bulkText.trim()) return;
    setFetchingBulk(true);

    const lines = bulkText.split('\n').map(l => l.trim()).filter(Boolean);

    if (lines.length === 0) {
      setFetchingBulk(false);
      return;
    }

    const fetchedVideos: SourceVideo[] = await Promise.all(lines.map(async (line) => {
      let isUrl = false;
      let urlStr = line;
      if (line.startsWith('http://') || line.startsWith('https://')) {
        isUrl = true;
      } else if (line.includes('.') && !line.includes(' ')) {
        isUrl = true;
        urlStr = 'https://' + line;
      }

      if (isUrl) {
        const vid = extractYoutubeIdBulk(urlStr);
        if (vid) {
          try {
            const res = await fetch(`https://www.youtube.com/oembed?url=${encodeURIComponent(urlStr)}&format=json`);
            if (res.ok) {
              const data = await res.json();
              return { id: crypto.randomUUID(), videoId: vid, title: data.title || 'YouTube Video', url: urlStr };
            }
          } catch (e) {}
          return { id: crypto.randomUUID(), videoId: vid, title: 'YouTube Video', url: urlStr };
        } else {
          let domain = 'Link';
          try { domain = new URL(urlStr).hostname; } catch {}
          return { id: crypto.randomUUID(), videoId: '', title: `Reading: ${domain}`, url: urlStr };
        }
      } else {
        return { id: crypto.randomUUID(), videoId: '', title: line, url: '' };
      }
    }));

    if (fetchedVideos.length > 0) {
      const newSource: StagedSource = {
        id: crypto.randomUUID(),
        title: 'Bulk Imported Items',
        type: 'bulk',
        videos: fetchedVideos,
        isExpanded: true,
        searchQuery: '',
        rangeInput: ''
      };
      setStagedSources(prev => [newSource, ...prev]);
      setBulkText('');

      const newSelected = new Set(selectedVideoIds);
      fetchedVideos.forEach(v => newSelected.add(v.id));
      setSelectedVideoIds(newSelected);
    } else { alert("Failed to process items."); }

    setFetchingBulk(false);
  };

  // ΓöÇΓöÇΓöÇ SOURCE SELECTION & FILTER LOGIC ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const updateSourceState = (sourceId: string, updates: Partial<StagedSource>) => {
    setStagedSources(prev => prev.map(s => s.id === sourceId ? { ...s, ...updates } : s));
  };

  const handleRangeChange = (sourceId: string, val: string) => {
    updateSourceState(sourceId, { rangeInput: val });
    const source = stagedSources.find(s => s.id === sourceId);
    if (!source || !val.trim()) return;

    const newSelected = new Set(selectedVideoIds);
    // First, clear all existing selections for this source
    source.videos.forEach(v => newSelected.delete(v.id));

    const max = source.videos.length;
    const parts = val.split(',');

    for (const part of parts) {
      const trimmed = part.trim();
      if (!trimmed) continue;

      if (trimmed.includes('-')) {
        const [startStr, endStr] = trimmed.split('-');
        const start = parseInt(startStr, 10);
        const end = parseInt(endStr, 10);
        if (!isNaN(start) && !isNaN(end)) {
          for (let i = start; i <= end; i++) {
            if (i >= 1 && i <= max) newSelected.add(source.videos[i - 1].id);
          }
        }
      } else {
        const num = parseInt(trimmed, 10);
        if (!isNaN(num) && num >= 1 && num <= max) newSelected.add(source.videos[num - 1].id);
      }
    }

    setSelectedVideoIds(newSelected);
  };

  const toggleVideoSelection = (id: string) => {
    const next = new Set(selectedVideoIds);
    if (next.has(id)) next.delete(id); else next.add(id);
    setSelectedVideoIds(next);
  };

  const toggleAllInSource = (sourceId: string, forceStatus?: boolean) => {
    const source = stagedSources.find(s => s.id === sourceId);
    if (!source) return;
    const next = new Set(selectedVideoIds);
    const filtered = getFilteredVideos(source);

    const shouldAdd = forceStatus !== undefined ? forceStatus : !filtered.every(v => next.has(v.id));

    filtered.forEach(v => {
      if (shouldAdd) next.add(v.id);
      else next.delete(v.id);
    });
    setSelectedVideoIds(next);
  };

  const removeSource = (id: string) => {
    setStagedSources(prev => prev.filter(s => s.id !== id));
  };

  const getFilteredVideos = (source: StagedSource) => {
    return source.videos.filter(v => !source.searchQuery.trim() || v.title.toLowerCase().includes(source.searchQuery.toLowerCase()));
  };

  // ΓöÇΓöÇΓöÇ ADD TO CANVAS LOGIC ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const getGlobalSelectedVideos = () => {
    return stagedSources.flatMap(s => s.videos).filter(v => selectedVideoIds.has(v.id));
  };

  const createTopicFromSelected = () => {
    const vids = getGlobalSelectedVideos();
    if (vids.length === 0) return;

    const newTopic: DraftTopic = {
      id: crypto.randomUUID(),
      title: `Custom Topic (${vids.length} items)`,
      videos: vids.map(v => ({ ...v, id: crypto.randomUUID() })) // clone for canvas
    };

    setDraftTopics(prev => [...prev, newTopic]);
    setSelectedVideoIds(new Set()); // Clear selection after use
  };

  const addSelectedToTopic = (targetTopicId: string) => {
    const vids = getGlobalSelectedVideos();
    if (vids.length === 0) return;

    setDraftTopics(prev => prev.map(t => {
      if (t.id === targetTopicId) {
        const cloned = vids.map(v => ({ ...v, id: crypto.randomUUID() }));
        return { ...t, videos: [...t.videos, ...cloned] };
      }
      return t;
    }));
    setSelectedVideoIds(new Set());
  };

  // Γ£¿ AI Auto-Structuring Logic (Heuristic Regex Based)
  const autoGroupTopics = () => {
    const vids = getGlobalSelectedVideos();
    if (vids.length === 0) { alert("Please select some videos first!"); return; }

    const chunks: DraftTopic[] = [];
    const regex = /^(?:chapter|week|lec(?:ture)?|part|module)\s*\d+[:\-]?\s*(.*)/i;

    let currentTopicTitle = "Group 1";
    let currentVideos: SourceVideo[] = [];
    let groupCount = 1;

    for (const v of vids) {
      const match = v.title.match(regex);
      if (match) {
        if (currentVideos.length > 0) {
          chunks.push({ id: crypto.randomUUID(), title: currentTopicTitle, videos: currentVideos });
          currentVideos = [];
        }
        groupCount++;
        currentTopicTitle = `Group ${groupCount}: ${match[1].trim()}`;
      }
      currentVideos.push({ ...v, id: crypto.randomUUID() });
    }

    if (currentVideos.length > 0) {
      chunks.push({ id: crypto.randomUUID(), title: currentTopicTitle, videos: currentVideos });
    }

    // Fallback if regex failed (i.e. we only have 1 chunk and it has too many videos)
    if (chunks.length === 1 && chunks[0].videos.length > 15) {
      const fallback: DraftTopic[] = [];
      const flat = chunks[0].videos;
      for (let i = 0; i < flat.length; i += 15) {
        fallback.push({
          id: crypto.randomUUID(),
          title: `Section ${Math.floor(i / 15) + 1}`,
          videos: flat.slice(i, i + 15)
        });
      }
      setDraftTopics(prev => [...prev, ...fallback]);
    } else {
      setDraftTopics(prev => [...prev, ...chunks]);
    }

    setSelectedVideoIds(new Set());
  };

  // ΓöÇΓöÇΓöÇ CANVAS LOGIC ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const handleDragEnd = (result: any) => {
    if (!result.destination) return;
    const { source, destination } = result;

    if (source.droppableId === destination.droppableId) {
      setDraftTopics(prev => prev.map(t => {
        if (t.id === source.droppableId) {
          const items = Array.from(t.videos);
          const [reorderedItem] = items.splice(source.index, 1);
          items.splice(destination.index, 0, reorderedItem);
          return { ...t, videos: items };
        }
        return t;
      }));
    } else {
      setDraftTopics(prev => {
        const newDrafts = [...prev];
        const sTopicIdx = newDrafts.findIndex(t => t.id === source.droppableId);
        const dTopicIdx = newDrafts.findIndex(t => t.id === destination.droppableId);
        if (sTopicIdx > -1 && dTopicIdx > -1) {
          const sItems = Array.from(newDrafts[sTopicIdx].videos);
          const dItems = Array.from(newDrafts[dTopicIdx].videos);
          const [removed] = sItems.splice(source.index, 1);
          dItems.splice(destination.index, 0, removed);
          newDrafts[sTopicIdx] = { ...newDrafts[sTopicIdx], videos: sItems };
          newDrafts[dTopicIdx] = { ...newDrafts[dTopicIdx], videos: dItems };
        }
        return newDrafts;
      });
    }
  };

  const createEmptyTopic = () => {
    if (!newTopicTitle.trim()) return;
    setDraftTopics(prev => [...prev, { id: crypto.randomUUID(), title: newTopicTitle, videos: [] }]);
    setNewTopicTitle('');
  };

  const removeTopic = (id: string) => setDraftTopics(prev => prev.filter(t => t.id !== id));
  const removeVideoFromTopic = (topicId: string, videoId: string) => {
    setDraftTopics(prev => prev.map(t => t.id === topicId ? { ...t, videos: t.videos.filter(v => v.id !== videoId) } : t));
  };

  // Total Duration Calculation
  const getTotalCurriculumDuration = () => {
    const totalSec = draftTopics.flatMap(t => t.videos).reduce((acc, v) => acc + parseDuration(v.durationStr || ''), 0);
    return formatTotalDuration(totalSec);
  };

  // ΓöÇΓöÇΓöÇ RENDER ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  return createPortal(
    <div data-lenis-prevent="true" style={{ position: 'fixed', inset: 0, zIndex: 100000, background: 'rgba(9,9,11,0.98)', display: 'flex', flexDirection: 'column' }}>

      {/* Mini Video Preview Overlay */}
      {previewVideoId && (
        <div style={{ position: 'fixed', bottom: '2rem', right: '2rem', width: '380px', aspectRatio: '16/9', background: '#000', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 25px 50px rgba(0,0,0,0.5)', zIndex: 100001, border: '1px solid rgba(255,255,255,0.1)' }}>
          <div style={{ position: 'absolute', top: '0.5rem', right: '0.5rem', zIndex: 10 }}>
            <button onClick={() => setPreviewVideoId(null)} style={{ background: 'rgba(0,0,0,0.6)', border: 'none', color: '#fff', borderRadius: '50%', padding: '0.4rem', cursor: 'pointer' }}><X size={14} /></button>
          </div>
          <iframe src={`https://www.youtube.com/embed/${previewVideoId}?autoplay=1`} frameBorder="0" allow="autoplay; encrypted-media" allowFullScreen style={{ width: '100%', height: '100%' }} />
        </div>
      )}

      {/* Header */}
