import { useEffect, useRef } from 'react';
import { sendSystemNotification } from '../utils/notifications';
import { auth } from '../services/firebase';

/**
 * useClassNotifications ΓÇö polls every 60s to check if any class starts
 * within the next 10 minutes. Fires both a local Web Notification and an
 * FCM push so the alert works even if the device screen is locked.
 *
 * The hook is intentionally lightweight:
 *  - No Firestore reads (subjects come from GlobalDataContext, already loaded)
 *  - A ref tracks already-notified class slots per session to prevent duplicates
 *
 * Data model expected on each subject:
 *   subject.schedule[dayIndex] = {
 *     classCount: number,
 *     labCount: number,
 *     startTimes: string[],  // e.g. ["09:00", "11:00"]  ΓÇö may be missing for old data
 *   }
 */
export const useClassNotifications = (subjects: any[]) => {
  // Tracks which class slots were already notified this session: "subjectId_day_slotIdx"
  const notifiedRef = useRef<Set<string>>(new Set());

  useEffect(() => {
    if (!subjects || subjects.length === 0) return;

    const check = () => {
      const user = auth.currentUser;
      if (!user) return;

      const now = new Date();
      const dayIdx = now.getDay().toString();
      const nowMinutes = now.getHours() * 60 + now.getMinutes();

      subjects.forEach(subject => {
        if (!subject.id || !subject.schedule) return;
        const slot = subject.schedule[dayIdx];
        if (!slot || !Array.isArray(slot.startTimes)) return;

        slot.startTimes.forEach((startTime: string, idx: number) => {
          if (!startTime) return;
          const [hStr, mStr] = startTime.split(':');
          const classMinutes = parseInt(hStr) * 60 + parseInt(mStr);
          const diff = classMinutes - nowMinutes;

          // Fire notification when class is 10ΓÇô11 min away (1-min window to avoid re-trigger)
          if (diff >= 10 && diff < 11) {
            const slotKey = `${subject.id}_${dayIdx}_${idx}`;
            if (notifiedRef.current.has(slotKey)) return;
            notifiedRef.current.add(slotKey);

            const title = `≡ƒôÜ Class in 10 min: ${subject.name}`;
            const body = `${subject.name} starts at ${startTime}. Get ready!`;

            // Web Notification (shows when tab is open/background)
            sendSystemNotification(title, { body }, false);
          }
        });
      });
    };

    // Run immediately on mount, then every 60 seconds
    check();
    const interval = window.setInterval(check, 60_000);
    return () => window.clearInterval(interval);
  }, [subjects]);
};

import { useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { toast } from 'sonner';
import { useGlobalData } from '../contexts/GlobalDataContext';

export const useContextReminders = () => {
  const location = useLocation();
  const { tasks, gymLogs } = useGlobalData();
  const hasShownGymReminder = useRef(false);
  const hasShownTodoReminder = useRef(false);

  useEffect(() => {
    // We delay the toast slightly so it appears after the page loads
    const timer = setTimeout(() => {
      const path = location.pathname;
      const now = new Date();

      if (path === '/gym') {
        const gymLoggedToday = gymLogs.some((l: any) => new Date(l.date).toDateString() === now.toDateString());
        if (!gymLoggedToday && !hasShownGymReminder.current) {
          toast.message('Zen AI Reminder ≡ƒºá', {
            description: "Don't forget to take your pre-workout! Let's crush today's session.",
            duration: 6000,
          });
          hasShownGymReminder.current = true;
        }
      }

      if (path === '/todo' || path === '/tasks') {
        const overdueTodos = tasks.filter(t => t.isOverdue && t.status !== 'completed');
        if (overdueTodos.length > 3 && !hasShownTodoReminder.current) {
          toast.message('Zen AI Reminder ≡ƒºá', {
            description: `You have ${overdueTodos.length} overdue tasks! Focus mode is highly recommended.`,
            duration: 6000,
          });
          hasShownTodoReminder.current = true;
        } else if (tasks.filter(t => t.status !== 'completed').length === 0 && tasks.length > 0) {
          // If they just opened the todo page and have 0 pending tasks
           toast.success("You've cleared all your tasks for today! Take a break.");
        }
      }

    }, 1000);

    return () => clearTimeout(timer);
  }, [location.pathname, tasks, gymLogs]);
};

import { useEffect, useRef } from 'react';
import { orchestrateAgent } from '../agent/orchestrator';
import { getLocalDateString } from '../utils/dateUtils';
import { toast } from 'sonner';
import { agentMemoryStore } from '../stores/agentMemoryStore';

const PROACTIVE_THROTTLE_MS = 60 * 60 * 1000;   // 1 hour between emergency action runs
const GHOST_THROTTLE_MS     = 24 * 60 * 60 * 1000; // 24 hours between ghost scans
const STORAGE_KEY    = 'zen_proactive_last_run';
const GHOST_SCAN_KEY = 'zen_ghost_last_scan';

/**
 * useProactiveAgent ΓÇö Fully Autonomous Productivity Engine
 *
 * Two independent loops that fire on app load:
 *
 * LOOP 1 ΓÇö Emergency Action Loop (throttle: 1hr)
 *   Triggered by overdue/today tasks. Issues AUTONOMOUS_ACTION_PROTOCOL to the
 *   full agent fleet. Agents TAKE REAL ACTIONS:
 *     ΓÇó ARGUS  ΓåÆ risk-scores each task, sends push notification for each CRITICAL item
 *     ΓÇó CHRONOS ΓåÆ finds free slot, blocks 90-min recovery event in Google Calendar
 *     ΓÇó HERMES    ΓåÆ reads Gmail for stakeholder threads, sends status update email
 *     ΓÇó AEGIS       ΓåÆ reports WHAT WAS DONE (not what the user should do)
 *
 * LOOP 2 ΓÇö Ghost Deadline Scan (throttle: 24hr)
 *   Silently scans inbox once per day. Creates tasks for untracked commitments.
 *   Sends one notification if ghost deadlines are found; silent otherwise.
 *
 * This is what takes ZenTrack from "reactive chatbot" to "autonomous AI agent."
 */
export const useProactiveAgent = (
  tasks: any[],
  calendarEvents: any[],
  setIsExecuting?: (b: boolean) => void
) => {
  const hasRun = useRef(false);

  useEffect(() => {
    if (!tasks || tasks.length === 0) return;
    if (hasRun.current) return;
    hasRun.current = true;

    // ΓöÇΓöÇΓöÇ LOOP 1: Emergency Action Loop ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const runEmergencyActionLoop = async () => {
      const lastRun = parseInt(localStorage.getItem(STORAGE_KEY) || '0', 10);
      if (Date.now() - lastRun < PROACTIVE_THROTTLE_MS) return;

      const today = getLocalDateString(new Date());
      const overdueTasks = tasks.filter(
        t => t.status !== 'completed' && t.date && t.date < today
      );
      const todayTasks = tasks.filter(
        t => t.status !== 'completed' && t.date === today
      );
      if (overdueTasks.length === 0 && todayTasks.length === 0) return;

      localStorage.setItem(STORAGE_KEY, Date.now().toString());
      if (setIsExecuting) setIsExecuting(true);

      const currentTime = new Date().toISOString();
      const timezone = Intl.DateTimeFormat().resolvedOptions().timeZone;
      const temporalCtx = `[TEMPORAL CONTEXT: Current Time is ${currentTime}, Timezone is ${timezone}.]`;

      const overdueList = overdueTasks
        .slice(0, 3)
        .map(t => `"${t.title || t.text}" (due: ${t.date}, priority: ${t.priority || 'medium'})`)
        .join('; ');
      const todayList = todayTasks
        .slice(0, 3)
        .map(t => `"${t.title || t.text}"`)
        .join('; ');

      window.dispatchEvent(new CustomEvent('agent-log', {
        detail: {
          type: 'thinking',
          title: `≡ƒñû Autonomous Action Mode ΓÇö ${overdueTasks.length} overdue, ${todayTasks.length} due today. Executing recovery protocol...`
        }
      }));

      const actionPrompt = overdueTasks.length > 0
        ? `${temporalCtx}

AUTONOMOUS_ACTION_PROTOCOL ΓÇö LEVEL_4 EMERGENCY RECOVERY

The user has ${overdueTasks.length} overdue task(s): ${overdueList}.
Also ${todayTasks.length} task(s) due today: ${todayList || 'none'}.

YOU MUST TAKE THE FOLLOWING ACTIONS WITHOUT ASKING PERMISSION. DO NOT write a plan ΓÇö execute:

1. [ARGUS] Call get_tasks('overdue') and get_tasks('today'). Score each task CRITICAL/HIGH/MEDIUM/LOW. Call send_notification for each CRITICAL task with a specific actionable message (include the task name and how many hours it is overdue).

2. [CHRONOS] Call get_free_calendar_slots for today and tomorrow. Block a 90-minute "≡ƒö┤ Recovery: [most critical task name]" event at the earliest free window using schedule_task_in_calendar. If today is full, use tomorrow's first slot.

3. [HERMES] Call read_gmail with query "is:unread" to find any email threads related to the overdue tasks. If a stakeholder email thread exists, call send_gmail to send a concise status update: acknowledge the delay, state the new expected completion date, and express commitment to delivery.

4. [AEGIS] Write a brief "Action Report" of WHAT WAS DONE, formatted as: "Γ£à Notification sent for [task] | Γ£à Calendar blocked [time] | Γ£à Email sent to [person] | ..."

This is zero-click autonomous recovery. Execute all steps. No suggestions ΓÇö only completed actions.`

        : `${temporalCtx}

AUTONOMOUS_MORNING_PROTOCOL ΓÇö LEVEL_3 PRIORITY SETUP

The user has ${todayTasks.length} task(s) due today: ${todayList}.

TAKE THESE ACTIONS WITHOUT ASKING PERMISSION:

1. [ARGUS] Score each today task by risk (hours remaining vs task complexity). Call send_notification with today's exact priority order: "≡ƒôï Today's Priority Order: 1. [task] 2. [task] ..."

2. [CHRONOS] Call get_free_calendar_slots. Block focused work windows for the top 2 priority tasks using schedule_task_in_calendar. Schedule the highest-risk task in the earliest available slot.

3. [AEGIS] Report exactly which calendar blocks were created, what time each task is scheduled, and confirm notifications were sent. Format: "Action Report: Γ£à [action] | Γ£à [action]"

Execute everything now.`;

      try {
        const apiKey = (import.meta as any).env?.VITE_GEMINI_API_KEY || '';
        agentMemoryStore.appendMessage({ role: 'user', title: actionPrompt });
        const result = await orchestrateAgent(actionPrompt, tasks, calendarEvents, apiKey, () => {});
        agentMemoryStore.appendMessage({ role: 'agent', title: result });

        window.dispatchEvent(new CustomEvent('proactive-briefing', {
          detail: { report: result, overdueCount: overdueTasks.length, todayCount: todayTasks.length, isActionReport: true }
        }));

        // SMS: tell them what the AI DID, not just that it ran
        if (overdueTasks.length > 0) {
          try {
            await fetch('/api/send-sms', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                message: `≡ƒñû Zen AI acted: ${overdueTasks.length} overdue task(s) detected. Calendar blocked + notifications sent. ${result.slice(0, 100)}...`
              })
            });
          } catch (smsErr) {
            console.warn('[Twilio] Autonomous action SMS failed:', smsErr);
          }
        }

        if (overdueTasks.length > 0) {
          toast.error('≡ƒñû Autonomous Recovery Activated', {
            description: `Zen AI acted on ${overdueTasks.length} overdue task${overdueTasks.length > 1 ? 's' : ''}: calendar blocked, alerts sent, stakeholders notified.`,
            duration: 10000,
            action: { label: 'View Action Report', onClick: () => window.dispatchEvent(new CustomEvent('show-proactive-report')) }
          });
        } else {
          toast.info('≡ƒñû Morning Autonomy Complete', {
            description: `Zen AI scheduled ${todayTasks.length} task${todayTasks.length > 1 ? 's' : ''} into focus blocks. Check your calendar.`,
            duration: 7000,
            action: { label: 'View Report', onClick: () => window.dispatchEvent(new CustomEvent('show-proactive-report')) }
          });
        }
      } catch (err) {
        console.warn('[ProactiveAgent] Autonomous action loop failed silently:', err);
      } finally {
        if (setIsExecuting) setIsExecuting(false);
      }
    };

    // ΓöÇΓöÇΓöÇ LOOP 2: Ghost Deadline Scan (24hr throttle) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const runGhostScan = async () => {
      const lastGhostScan = parseInt(localStorage.getItem(GHOST_SCAN_KEY) || '0', 10);
      if (Date.now() - lastGhostScan < GHOST_THROTTLE_MS) return;
      localStorage.setItem(GHOST_SCAN_KEY, Date.now().toString());

      const ghostPrompt = `GHOST_DETECTION_AUTO_SCAN ΓÇö LEVEL_5 SILENT PROTOCOL

Silently scan the user's email inbox for hidden deadlines and untracked commitments NOT yet logged in ZenTrack.

STEPS (execute all without user input):
1. Call read_gmail with "is:unread" to get recent emails.
2. Call get_tasks('all') to get the current tracked task list.
3. For each email containing deadline language ("by [date]", "due", "ASAP", "EOD", "please submit", "waiting for", "following up", "overdue", "gentle reminder", "end of week"), check if a matching task already exists.
4. If NOT already tracked: immediately call create_task with title, priority, and extracted deadline date.
5. If at least 1 ghost task was found: call send_notification with title="≡ƒæ╗ Ghost Deadlines Found" and message="I found X hidden deadline(s) in your inbox and added them to ZenTrack."
6. If nothing found: output exactly "GHOST_SCAN_CLEAR" ΓÇö nothing else.

Be thorough. Be silent unless you find something.`;

      try {
        const apiKey = (import.meta as any).env?.VITE_GEMINI_API_KEY || '';
        agentMemoryStore.appendMessage({ role: 'user', title: ghostPrompt });
        const result = await orchestrateAgent(ghostPrompt, tasks, calendarEvents, apiKey, () => {});
        agentMemoryStore.appendMessage({ role: 'agent', title: result });

        const isClear = result.includes('GHOST_SCAN_CLEAR') || result.toLowerCase().includes('no ghost') || result.toLowerCase().includes('no hidden');
        if (!isClear) {
          const countMatch = result.match(/found\s+(\d+)/i) || result.match(/(\d+)\s+(?:ghost|hidden)/i);
          const count = countMatch ? parseInt(countMatch[1]) : null;
          window.dispatchEvent(new CustomEvent('ghost-scan-complete', { detail: { result, count } }));
        }
      } catch (err) {
        console.warn('[GhostScanner] Auto-scan failed silently:', err);
        // Retry in 1h instead of 24h on failure
        localStorage.setItem(GHOST_SCAN_KEY, (Date.now() - GHOST_THROTTLE_MS + 60 * 60 * 1000).toString());
      }
    };

    // Stagger loops to prevent simultaneous API hits
    const emergencyTimer = setTimeout(runEmergencyActionLoop, 3000);
    const ghostTimer     = setTimeout(runGhostScan, 8000); // 5s after emergency loop

    return () => {
      clearTimeout(emergencyTimer);
      clearTimeout(ghostTimer);
    };
  }, [tasks, calendarEvents, setIsExecuting]);
};

import { useEffect, useMemo } from 'react';
import { getLocalDateString } from '../utils/dateUtils';

type UrgencyState = 'state-calm' | 'state-active' | 'state-critical';

/**
 * Computes the global urgency state from the user's task list
 * and applies it as a class on :root, morphing the entire app's color palette.
 *
 * - state-critical: Any overdue tasks (Crimson / Magenta)
 * - state-active:   Tasks due today (Sunset Orange / Mango)
 * - state-calm:     No urgent deadlines (Bioluminescent Cyan)
 */
export const useUrgencyState = (tasks: any[]): UrgencyState => {
  const urgencyState = useMemo<UrgencyState>(() => {
    if (!tasks || tasks.length === 0) return 'state-calm';

    const today = getLocalDateString(new Date());

    const hasOverdue = tasks.some(
      t => t.status !== 'completed' && t.date && t.date < today
    );
    if (hasOverdue) return 'state-critical';

    const hasUrgentToday = tasks.some(
      t => t.status !== 'completed' && t.date === today
    );
    if (hasUrgentToday) return 'state-active';

    return 'state-calm';
  }, [tasks]);

  useEffect(() => {
    const root = document.documentElement;
    // Remove previous urgency states
    root.classList.remove('state-calm', 'state-active', 'state-critical');
    root.classList.add(urgencyState);

    return () => {
      root.classList.remove('state-calm', 'state-active', 'state-critical');
    };
  }, [urgencyState]);

  return urgencyState;
};

import * as pdfjsLib from 'pdfjs-dist';
import * as mammoth from 'mammoth';

// Configure the worker for pdfjs-dist via a public CDN
// This avoids complex Vite worker configurations and large chunk sizes.
pdfjsLib.GlobalWorkerOptions.workerSrc = `//cdnjs.cloudflare.com/ajax/libs/pdf.js/${pdfjsLib.version}/pdf.worker.min.js`;

/**
 * Extracts all text from a given PDF URL by fetching it and parsing pages.
 */
export const extractTextFromPdf = async (url: string): Promise<string> => {
  try {
    const loadingTask = pdfjsLib.getDocument(url);
    const pdf = await loadingTask.promise;
    let fullText = '';

    // Process each page sequentially
    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const content = await page.getTextContent();
      const strings = content.items.map((item: any) => item.str);
      fullText += strings.join(' ') + '\n';
    }

    return fullText.trim();
  } catch (error) {
    console.error('Failed to parse PDF:', error);
    throw new Error('Failed to extract text from PDF file.');
  }
};

/**
 * Extracts raw text from a given DOCX URL by fetching it as an ArrayBuffer.
 */
export const extractTextFromDocx = async (url: string): Promise<string> => {
  try {
    const response = await fetch(url);
    const arrayBuffer = await response.arrayBuffer();
    const result = await mammoth.extractRawText({ arrayBuffer });
    return result.value.trim();
  } catch (error) {
    console.error('Failed to parse DOCX:', error);
    throw new Error('Failed to extract text from DOCX file.');
  }
};

