// ΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export const sleep = (ms: number) => new Promise(r => setTimeout(r, ms));

// ΓöÇΓöÇ Global Concurrency Semaphore ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// This is the PRIMARY fix for the thundering-herd / key exhaustion problem.
// All callWithFallback calls share this counter. When too many agents are firing
// simultaneously, excess callers wait with random jitter before proceeding.
// This prevents N parallel agents from all hitting the API at the exact same ms.
const MAX_CONCURRENT_API_CALLS = 3; // Max simultaneous Gemini API calls across ALL agents
let _activeApiCalls = 0;

const acquireSemaphore = async (): Promise<void> => {
  const MAX_WAIT_MS = 30_000; // max 30s wait in queue
  const startedAt = Date.now();
  while (_activeApiCalls >= MAX_CONCURRENT_API_CALLS) {
    if (Date.now() - startedAt > MAX_WAIT_MS) {
      // Timeout: proceed anyway rather than deadlocking
      console.warn('[ZenAI] Semaphore wait timeout ΓÇö proceeding anyway to avoid deadlock.');
      break;
    }
    // Wait with random jitter so multiple queued calls don't all wake at the same time
    const jitter = 200 + Math.random() * 300;
    await sleep(jitter);
  }
  _activeApiCalls++;
};

const releaseSemaphore = () => {
  _activeApiCalls = Math.max(0, _activeApiCalls - 1);
};

// ΓöÇΓöÇ Per-key cooldown tracker ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// When a key hits 429, mark it unavailable for KEY_COOLDOWN_MS.
// All subsequent callWithFallback calls skip that key until it cools down.
// This prevents the 1/8ΓåÆ2/8ΓåÆ8/8 waterfall exhaustion spiral.
const KEY_COOLDOWN_MS = 62_000; // 62s ΓÇö just over Gemini's typical 60s 429 window
const keyCooldownUntil = new Map<string, number>(); // token (first 8 chars) ΓåÆ available-at timestamp

const isKeyAvailable = (token: string): boolean => {
  const key = token.substring(0, 8); // use prefix as map key (never log full key)
  const until = keyCooldownUntil.get(key);
  if (!until) return true;
  if (Date.now() >= until) {
    keyCooldownUntil.delete(key);
    return true;
  }
  return false;
};

const markKeyCooling = (token: string, reason: string, customCooldownMs?: number) => {
  const key = token.substring(0, 8);
  // Γ£à FIXED: Use dynamic cooldown from Retry-After header if available,
  // otherwise fall back to the default 62s window.
  const cooldownMs = customCooldownMs ?? KEY_COOLDOWN_MS;
  const until = Date.now() + cooldownMs;
  keyCooldownUntil.set(key, until);
  console.warn(`[ZenAI] Key ...${key} rate-limited. Cooling for ${Math.ceil(cooldownMs / 1000)}s. Reason: ${reason.substring(0, 60)}`);
};

const isRateLimit = (err: any): boolean => {
  const msg = (err?.message || '').toLowerCase();
  return msg.includes('429') || msg.includes('quota') || msg.includes('rate limit') || msg.includes('resource_exhausted');
};

const isAuthError = (err: any): boolean => {
  const msg = (err?.message || '').toLowerCase();
  return msg.includes('401') || msg.includes('403') || msg.includes('invalid authentication') || msg.includes('authentication credentials') || msg.includes('permission denied');
};

const isModelNotFound = (err: any): boolean => {
  const msg = (err?.message || '').toLowerCase();
  return msg.includes('404') || msg.includes('not found');
};

const isOverload = (err: any): boolean => {
  const msg = (err?.message || '').toLowerCase();
  return msg.includes('503') || msg.includes('overload') || msg.includes('high demand') || msg.includes('unavailable');
};

// ΓöÇΓöÇ True round-robin key pointer ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// globalKeyIndex is the NEXT key to try. Each callWithFallback call picks the
// first available (non-cooling) key starting at globalKeyIndex, then advances
// the pointer. This distributes load across parallel agents correctly.
export let globalKeyIndex = 0;

export const takeNextKeyIndex = (): number => {
  const current = globalKeyIndex;
  globalKeyIndex = (globalKeyIndex + 1) % Math.max(allKeys.length, 1);
  return current;
};

/**
 * Picks the next available (non-cooling) shared API key using round-robin.
 * If all keys are cooling, waits for the soonest one to become available.
 * Returns { token, index } or null if no shared keys configured.
 */
const pickNextSharedKey = async (): Promise<{ token: string; index: number } | null> => {
  if (allKeys.length === 0) return null;
  const startIdx = globalKeyIndex;
  for (let attempt = 0; attempt < allKeys.length; attempt++) {
    const idx = (startIdx + attempt) % allKeys.length;
    const token = allKeys[idx];
    if (isKeyAvailable(token)) {
      // Advance global pointer so the NEXT call starts after this key
      globalKeyIndex = (idx + 1) % allKeys.length;
      return { token, index: idx };
    }
  }
  // All shared keys are cooling ΓÇö find the one that comes back soonest
  let soonestToken = allKeys[0];
  let soonestIdx   = 0;
  let soonestTime  = keyCooldownUntil.get(allKeys[0].substring(0, 8)) ?? 0;
  for (let i = 1; i < allKeys.length; i++) {
    const t = keyCooldownUntil.get(allKeys[i].substring(0, 8)) ?? 0;
    if (t < soonestTime) { soonestTime = t; soonestToken = allKeys[i]; soonestIdx = i; }
  }
  // Γ£à FIXED: Actually WAIT for the cooldown to expire before returning the key.
  // The old code returned the dead key immediately, causing the caller to fire
  // another instant 429 at the same key, wasting a retry slot.
  const waitMs = Math.max(0, soonestTime - Date.now());
  if (waitMs > 0) {
    console.warn(`[ZenAI] All ${allKeys.length} shared keys cooling. Waiting ${Math.ceil(waitMs / 1000)}s for key ...${soonestToken.substring(0, 8)} to recover.`);
    if (typeof window !== 'undefined') {
      window.dispatchEvent(new CustomEvent('agent-log', {
        detail: { type: 'thinking', title: `ΓÅ│ All keys cooling. Recovering in ${Math.ceil(waitMs / 1000)}s...` }
      }));
    }
    await sleep(waitMs + 500); // +500ms buffer to be safe
    keyCooldownUntil.delete(soonestToken.substring(0, 8)); // Clear its cooldown
  }
  return { token: soonestToken, index: soonestIdx };
};

/**
 * Core AI caller ΓÇö redesigned for correct key load distribution:
 *
 * STRATEGY:
 *  1. Personal OAuth key first (if available)
 *  2. ONE shared key per request (true round-robin, no waterfall)
 *  3. If that key 429s ΓåÆ mark it cooling, pick next available key, one retry
 *  4. Max 3 key rotations per request (not 8)
 *  5. Model fallback: if model 404s or overloads, try next model in priority list
 *
 * PARALLEL AGENT SAFETY:
 *  - keyCooldownUntil is module-level ΓåÆ shared across all simultaneous callWithFallback calls
 *  - pickNextSharedKey() atomically advances globalKeyIndex ΓåÆ no two parallel calls grab the same key
 */
/**
 * PUBLIC: Full semaphore-protected API caller for top-level agent calls.
 * Acquires a global slot, runs the request, then releases the slot.
 * Use this for all orchestrator-level agent invocations.
 */
export const callWithFallback = async (
  buildRequest: (genAI: GoogleGenerativeAI, modelName: string) => Promise<any>
): Promise<any> => {
  // Γ£à Acquire global semaphore ΓÇö prevents thundering herd from parallel agents
  await acquireSemaphore();
  try {
    return await _callWithFallbackInner(buildRequest);
  } finally {
    releaseSemaphore();
  }
};

/**
 * PUBLIC: Semaphore-BYPASSED API caller for sub-agent delegation.
 *
 * Γ£à CRITICAL FIX: When a top-level agent calls delegate_task, it already holds
 * a semaphore slot. If the sub-agent tries to acquire another slot via
 * callWithFallback, it may block indefinitely if the pool is full (3 slots).
 * A TITAN delegating to HERMES + CHRONOS would consume all 3 slots, hard-
 * blocking every other top-level agent.
 *
 * Sub-delegated calls must skip semaphore acquisition because the parent
 * agent's slot implicitly covers the sub-agent's work.
 */
export const callWithFallbackUnthrottled = async (
  buildRequest: (genAI: GoogleGenerativeAI, modelName: string) => Promise<any>
): Promise<any> => {
  return await _callWithFallbackInner(buildRequest);
};

// ΓöÇΓöÇ Startup Model Health Check ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// Proactively validates which models are actually available before any user
// request arrives. Preview models (e.g. flash-lite-preview) can be deprecated
// without notice. Models that fail the ping are removed from priority lists.
const _unavailableModels = new Set<string>();

export const getEffectivePriorityList = (isPersonal: boolean): string[] => {
  const base = isPersonal ? PERSONAL_MODEL_PRIORITY : SHARED_MODEL_PRIORITY;
  return base.filter(m => !_unavailableModels.has(m));
};

export const runModelHealthCheck = async (): Promise<void> => {
  if (allKeys.length === 0) return; // no keys to test with
  const testKey = allKeys[0];
  const allModels = Array.from(new Set([...SHARED_MODEL_PRIORITY, ...PERSONAL_MODEL_PRIORITY]));
  const testGenAI = new GoogleGenerativeAI(testKey);

  console.log('[ZenAI] ≡ƒñû Running startup model health check...');
  await Promise.allSettled(allModels.map(async (modelId) => {
    try {
      const model = testGenAI.getGenerativeModel({ model: modelId });
      // Minimal ping: just ask for 1 token
      await model.generateContent({ contents: [{ role: 'user', parts: [{ text: 'hi' }] }] });
      console.log(`[ZenAI] Γ£à Model available: ${modelId}`);
    } catch (err: any) {
      if (isModelNotFound(err) || err?.message?.includes('deprecated')) {
        _unavailableModels.add(modelId);
        console.warn(`[ZenAI] ΓÜá∩╕Å Model unavailable (marked skip): ${modelId}`);
      }
      // Rate limits / overloads are transient ΓÇö don't mark as unavailable
    }
  }));
  console.log(`[ZenAI] Health check done. Unavailable: [${[..._unavailableModels].join(', ') || 'none'}]`);
};

// Internal implementation ΓÇö separated so semaphore wraps the entire execution
const _callWithFallbackInner = async (
  buildRequest: (genAI: GoogleGenerativeAI, modelName: string) => Promise<any>
): Promise<any> => {
  const personalKey = getActiveGeminiKey();

  if (!personalKey && allKeys.length === 0) {
    throw new Error('No Gemini API key found. Add your API key in Settings ΓåÆ AI Key.');
  }

  // Model priority list ΓÇö uses health-check-filtered list so deprecated/unavailable
  // preview models (e.g. flash-lite-preview) are automatically excluded at startup.
  const isPersonalRequest = !!personalKey;
  const ordered = getEffectivePriorityList(isPersonalRequest);
  if (ordered.length === 0) {
    // All models marked unavailable ΓÇö use full list as emergency fallback
    ordered.push(...(isPersonalRequest ? PERSONAL_MODEL_PRIORITY : SHARED_MODEL_PRIORITY));
  }

  let lastError: any;
  let hitQuota = false;

  for (let mi = 0; mi < ordered.length; mi++) {
    const modelName = ordered[mi];

    // ΓöÇΓöÇ Attempt 1: personal OAuth key (if valid) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    if (personalKey) {
      // Re-check at time of use ΓÇö token may have expired
      const freshToken = getActiveGeminiKey();
      if (!freshToken) {
        if (typeof window !== 'undefined') {
          window.dispatchEvent(new CustomEvent('agent-log', {
            detail: { type: 'thinking', title: '≡ƒöä Personal token expired. Using shared key pool...' }
          }));
        }
      } else {
        try {
          const genAI = new GoogleGenerativeAI('oauth_dummy_key');
          const result = await buildRequest(genAI, modelName);
          return result;
        } catch (err: any) {
          lastError = err;
          const msg = String(err?.message || '').toLowerCase();

          if (msg.includes('personal_token_unavailable') || isAuthError(err)) {
            // Personal key failed ΓÇö fall through to shared pool silently
          } else if (isModelNotFound(err)) {
            break; // this model doesn't exist ΓåÆ try next model
          } else if (isOverload(err)) {
            break; // overloaded ΓåÆ try next model
          } else if (!isRateLimit(err)) {
            throw err; // non-retryable
          }
          // 429 on personal key ΓåÆ fall through to shared key
          if (typeof window !== 'undefined') {
            window.dispatchEvent(new CustomEvent('agent-log', {
              detail: { type: 'thinking', title: `ΓÜá∩╕Å Personal quota exceeded for ${modelName}. Using shared pool...` }
            }));
          }
          await sleep(1500);
        }
      }
    }

    // ΓöÇΓöÇ Attempt 2-N: shared key pool (true round-robin) ΓöÇΓöÇ
    // Max 2 key rotations per request ΓÇö we must NOT exhaust all 8 keys per failed request.
    // With the global semaphore, only 3 agents run at once, so at most 6 key slots are used
    // per second rather than 24.
    const MAX_KEY_ROTATIONS = Math.min(2, Math.max(1, allKeys.length));
    let rotationsUsed = 0;

    while (rotationsUsed < MAX_KEY_ROTATIONS) {
      const keyObj = await pickNextSharedKey(); // Γ£à Now async ΓÇö properly awaits cooldowns
      if (!keyObj) break; // no shared keys configured

      // If all keys are cooling, pickNextSharedKey already waited.
      // No additional wait needed here ΓÇö trust the semaphore + async pickNextSharedKey.

      try {
        const genAI  = new GoogleGenerativeAI(keyObj.token);
        const result = await buildRequest(genAI, modelName);
        return result; // Γ£à success
      } catch (err: any) {
        lastError = err;

        if (isRateLimit(err)) {
          hitQuota = true;
          // Γ£à Parse Retry-After header for exact cooldown duration from the API.
          // This is far more accurate than a hardcoded 62s guess.
          let retryAfterMs: number | undefined;
          try {
            // Gemini SDK wraps the response ΓÇö try multiple known paths
            const retryAfterHeader =
              err?.response?.headers?.get?.('Retry-After') ||
              err?.message?.match(/retry[\s-]?after[:\s]*(\d+)/i)?.[1];
            if (retryAfterHeader) {
              retryAfterMs = parseInt(String(retryAfterHeader), 10) * 1000;
              console.log(`[ZenAI] Parsed Retry-After: ${Math.ceil(retryAfterMs / 1000)}s`);
            }
          } catch { /* ignore header parse errors */ }
          markKeyCooling(keyObj.token, err.message, retryAfterMs);
          rotationsUsed++;
          if (rotationsUsed < MAX_KEY_ROTATIONS) {
            // Small delay before trying next key ΓÇö prevents thundering-herd
            const label = `shared key [${keyObj.index + 1}/${allKeys.length}]`;
            console.warn(`[ZenAI] ${label} 429 ΓÇö rotating to next available key (${rotationsUsed}/${MAX_KEY_ROTATIONS})`);
            if (typeof window !== 'undefined') {
              window.dispatchEvent(new CustomEvent('agent-log', {
                detail: { type: 'thinking', title: `Γå⌐ Key ${keyObj.index + 1} rate-limited. Trying next...` }
              }));
            }
            // Exponential backoff with jitter to prevent parallel agent thundering herds
            const baseDelay = 1500 * Math.pow(2, rotationsUsed);
            const jitter = Math.random() * 1000;
            const backoffMs = baseDelay + jitter;
            console.warn(`[ZenAI] Applying exponential backoff of ${Math.round(backoffMs)}ms before next key rotation.`);
            await sleep(backoffMs);
            continue;
          }
          break; // used all rotations ΓåÆ try next model
        }

        if (isModelNotFound(err)) break;  // model not available ΓåÆ try next model
        if (isOverload(err))    break;    // server overloaded ΓåÆ try next model
        if (isAuthError(err)) { rotationsUsed++; continue; } // invalid key ΓåÆ skip
        throw err; // non-retryable error
      }
    }

    // All key attempts for this model exhausted. Brief delay then try next model.
    if (mi < ordered.length - 1) {
      let delay = Math.min(1200 * (mi + 1), 4000);
      if (lastError) {
        const retryMatch = String(lastError.message).match(/retry[\s-]?after[:\s]*(\d+)/i);
        if (retryMatch?.[1]) delay = Math.min(parseInt(retryMatch[1], 10) * 1000, 8_000);
      }
      console.warn(`[ZenAI] ${modelName} exhausted. Trying ${ordered[mi + 1]} in ${delay}ms`);
      await sleep(delay);
    }
  }

  const finalMsg = String(lastError?.message || '').toLowerCase();
  if (finalMsg.includes('503') || finalMsg.includes('overload') || finalMsg.includes('high demand')) {
    throw new Error('AI is currently overloaded. Please try again in a moment.');
  }
  if (finalMsg.includes('401') || finalMsg.includes('invalid authentication') || finalMsg.includes('authentication credentials')) {
    if (personalKey) {
      setAuthExpired();
      throw new Error('Your Gemini OAuth session has expired. Please reconnect your Google account.');
    }
    throw new Error('Gemini API key is invalid. Please update VITE_GEMINI_API_KEY in your environment settings.');
  }

  // ΓöÇΓöÇ All models and keys exhausted ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  if (hitQuota) {
    if (typeof window !== 'undefined') {
      window.dispatchEvent(new CustomEvent('agent-log', {
        detail: { type: 'thinking', title: 'ΓÜá∩╕Å Rate limits hit. Please wait ~60s before retrying.' }
      }));
    }
    const coolingCount = [...keyCooldownUntil.values()].filter(t => t > Date.now()).length;
    throw new Error(
      coolingCount > 0
        ? `${coolingCount}/${allKeys.length} API key(s) are rate-limited. They auto-recover in ~60s. Add more keys in .env ΓåÆ VITE_GEMINI_API_KEY for higher throughput.`
        : 'AI quota reached. Add your own Gemini API key in Settings for uninterrupted access.'
    );
  }

  throw new Error(lastError?.message || 'AI failed to respond. Please try again.');
};



// ΓöÇΓöÇ Robust Chat Wrapper ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// Wraps a Gemini chat session with:
//  1. Model fallback ΓÇö tries every model in MODEL_PRIORITY
//  2. Key rotation ΓÇö tries every API key per model
//  3. History preservation ΓÇö stores initial seed so rebuilds always have valid history
//  4. History validation ΓÇö ensures first message is always role 'user'
export class RobustChatSession {
  private session: any;
  private modelName: string;
  private modelIndex: number;
  private systemPrompt: string;
  private keyIndex = 0;
  private genConfig: any;
  private seedHistory: any[];  // stored at creation so rebuilds are safe

  constructor(
    initialSession: any,
    modelName: string,
    systemPrompt: string,
    genConfig: any = { temperature: 0.65 },
    seedHistory: any[] = []
  ) {
    this.session      = initialSession;
    this.modelName    = modelName;
    this.modelIndex   = Math.max(0, MODEL_PRIORITY.indexOf(modelName));
    this.systemPrompt = systemPrompt;
    this.genConfig    = genConfig;
    this.seedHistory  = seedHistory;
  }

  async getHistory() {
    try {
      const h = await this.session.getHistory();
      return Array.isArray(h) && h.length > 0 ? h : this.seedHistory;
    } catch {
      return this.seedHistory;
    }
  }

  // Validate history: must start with 'user' role and alternate correctly
  private sanitizeHistory(history: any[]): any[] {
    if (!Array.isArray(history) || history.length === 0) return this.seedHistory;
    // If first entry isn't 'user', use the stored seed instead
    if (history[0]?.role !== 'user') return this.seedHistory;
    return history;
  }

  private async rebuildSession(modelName: string, keyIndex: number, history: any[]) {
    const safeHistory = this.sanitizeHistory(history);
    const genAI = new GoogleGenerativeAI(allKeys[keyIndex] || allKeys[0]);
    const model = genAI.getGenerativeModel({
      model: modelName,
      systemInstruction: this.systemPrompt,
      generationConfig: this.genConfig,
      safetySettings: SAFETY_SETTINGS,
    });
    return model.startChat({ history: safeHistory });
  }

  async sendMessageStream(msg: string, onChunk: (title: string) => void): Promise<{ title: string, model: string }> {
    let lastError: any;
    for (let mi = this.modelIndex; mi < MODEL_PRIORITY.length; mi++) {
      const modelName = MODEL_PRIORITY[mi];
      const MAX_KEY_ROTATIONS = Math.min(3, allKeys.length || 1);
      let rotationsUsed = 0;

      while (rotationsUsed < MAX_KEY_ROTATIONS) {
        const keyObj = pickNextSharedKey();
        const keyToken = keyObj ? keyObj.token : (allKeys[0] || '');
        const keyIdx = keyObj ? keyObj.index : 0;

        if (keyObj && !isKeyAvailable(keyObj.token)) {
          const until  = keyCooldownUntil.get(keyObj.token.substring(0, 8)) ?? Date.now();
          const waitMs = Math.min(Math.max(0, until - Date.now()), 8_000);
          if (waitMs > 0) {
            console.warn(`[ZenAI Stream] Waiting ${Math.ceil(waitMs / 1000)}s for cooldown...`);
            await sleep(waitMs);
          }
        }

        try {
          if (mi !== this.modelIndex || keyIdx !== this.keyIndex || rotationsUsed > 0) {
            const history = await this.getHistory();
            this.session    = await this.rebuildSession(modelName, keyIdx, history);
            this.modelName  = modelName;
            this.modelIndex = mi;
            this.keyIndex   = keyIdx;
          }

          const result = await this.session.sendMessageStream(msg);
          let fullText = '';
          let sawFinish = false;
          for await (const chunk of result.stream) {
            const chunkText = chunk.text();
            fullText += chunkText;
            onChunk(fullText);
            if (chunk.candidates?.[0]?.finishReason) {
              sawFinish = true;
            }
          }
          if (fullText.length > 0 && !sawFinish) {
            throw new Error('STREAM_ABORTED_NO_FINISH_REASON');
          }
          setPreferredModel(modelName);
          return { title: fullText, model: modelName };
        } catch (err: any) {
          lastError = err;
          const errMsg = String(err?.message || '').toLowerCase();
          const isAuth = errMsg.includes('401') || errMsg.includes('invalid authentication') || errMsg.includes('authentication credentials');
          const isNotFound = errMsg.includes('404') || errMsg.includes('not found');
          const isRateLimit = errMsg.includes('429') || errMsg.includes('quota') || errMsg.includes('rate limit') || errMsg.includes('resource_exhausted');
          const isOverload = errMsg.includes('503') || errMsg.includes('overload') || errMsg.includes('high demand');

          if (isAuth) {
            console.warn(`[ZenAI Stream] ${modelName} auth error (key ${keyIdx}), trying next key`);
            rotationsUsed++;
            continue;
          }

          if (isNotFound) {
            console.warn(`[ZenAI Stream] ${modelName} 404 not found, trying next model`);
            break;
          }

          if (errMsg.includes('first content should be with role') || errMsg.includes('role \'user\'')) {
            console.warn(`[ZenAI Stream] History role error, resetting to seed history`);
            try {
              this.session = await this.rebuildSession(modelName, keyIdx, this.seedHistory);
              const retryResult = await this.session.sendMessageStream(msg);
              let ft = '';
              let sawRetryFinish = false;
              for await (const chunk of retryResult.stream) {
                ft += chunk.text();
                onChunk(ft);
                if (chunk.candidates?.[0]?.finishReason) sawRetryFinish = true;
              }
              if (ft.length > 0 && !sawRetryFinish) {
                throw new Error('STREAM_ABORTED_NO_FINISH_REASON');
              }
              return { title: ft, model: modelName };
            } catch (e: any) { lastError = e; }
            break;
          }

          if (isRateLimit) {
            console.warn(`[ZenAI Stream] ${modelName} rate limited (key ${keyIdx + 1}/${allKeys.length})`);
            if (keyObj) {
              markKeyCooling(keyObj.token, err.message);
            }
            rotationsUsed++;
            if (rotationsUsed < MAX_KEY_ROTATIONS) {
              await sleep(400);
              continue;
            }
            break;
          }

          if (isOverload) {
            console.warn(`[ZenAI Stream] ${modelName} overloaded, trying next model`);
            await sleep(400);
            break;
          }

          throw new Error(err.message || 'AI failed to respond. Please try again.');
        }
      }
    }
    throw lastError || new Error('All models exhausted in stream.');
  }

  async sendMessage(msg: string) {
    let lastError: any;
    for (let mi = this.modelIndex; mi < MODEL_PRIORITY.length; mi++) {
      const modelName = MODEL_PRIORITY[mi];
      const MAX_KEY_ROTATIONS = Math.min(3, allKeys.length || 1);
      let rotationsUsed = 0;

      while (rotationsUsed < MAX_KEY_ROTATIONS) {
        const keyObj = pickNextSharedKey();
        const keyToken = keyObj ? keyObj.token : (allKeys[0] || '');
        const keyIdx = keyObj ? keyObj.index : 0;

        if (keyObj && !isKeyAvailable(keyObj.token)) {
          const until  = keyCooldownUntil.get(keyObj.token.substring(0, 8)) ?? Date.now();
          const waitMs = Math.min(Math.max(0, until - Date.now()), 8_000);
          if (waitMs > 0) {
            console.warn(`[ZenAI Chat] Waiting ${Math.ceil(waitMs / 1000)}s for cooldown...`);
            await sleep(waitMs);
          }
        }

        try {
          if (mi !== this.modelIndex || keyIdx !== this.keyIndex || rotationsUsed > 0) {
            const history = await this.getHistory();
            this.session = await this.rebuildSession(modelName, keyIdx, history);
            this.modelName = modelName;
            this.modelIndex = mi;
            this.keyIndex = keyIdx;
          }

          const result = await this.session.sendMessage(msg);
          setPreferredModel(modelName);
          return result;
        } catch (err: any) {
          lastError = err;
          const errMsg = String(err?.message || '').toLowerCase();

          const isAuth      = errMsg.includes('401') || errMsg.includes('invalid authentication') ||
                              errMsg.includes('authentication credentials');
          const isNotFound   = errMsg.includes('404') || errMsg.includes('not found');
          const isRateLimit  = errMsg.includes('429') || errMsg.includes('quota') || errMsg.includes('rate limit') || errMsg.includes('resource_exhausted');
          const isOverload   = errMsg.includes('503') || errMsg.includes('overload') || errMsg.includes('high demand');
          const isHistoryBad = errMsg.includes('first content should be with role') || errMsg.includes('role \'user\'');

          if (isAuth) {
            console.warn(`[ZenAI Chat] ${modelName} auth error (key ${keyIdx}), trying next key`);
            rotationsUsed++;
            continue;
          }

          if (isNotFound) {
            console.warn(`[ZenAI Chat] ${modelName} 404 not found, trying next model`);
            break;
          }

          if (isHistoryBad) {
            console.warn(`[ZenAI Chat] History role error, resetting to seed history`);
            try {
              this.session = await this.rebuildSession(modelName, keyIdx, this.seedHistory);
              const result = await this.session.sendMessage(msg);
              setPreferredModel(modelName);
              return result;
            } catch { /* fall through to next model */ }
            break;
          }

          if (isRateLimit) {
            console.warn(`[ZenAI Chat] ${modelName} rate limited (key ${keyIdx + 1}/${allKeys.length})`);
            if (keyObj) {
              markKeyCooling(keyObj.token, err.message);
            }
            rotationsUsed++;
            if (rotationsUsed < MAX_KEY_ROTATIONS) {
              await sleep(400);
              continue;
            }
            break;
          }

          if (isOverload) {
            console.warn(`[ZenAI Chat] ${modelName} overloaded, trying next model`);
            await sleep(400);
            break;
          }

          throw new Error(err.message || 'AI failed to respond. Please try again.');
        }
      }
    }

    console.error('[ZenAI Chat] All models failed:', lastError?.message);
    throw new Error('AI is temporarily unavailable. Please try again in a moment.');
  }
}


/**
 * Robustly parse JSON from an AI response.
 * Handles markdown fences, leading/trailing text, escaped JSON strings.
 */
export const parseAIJson = (text: string): any => {
  if (!text || typeof text !== 'string') throw new Error('parseAIJson received empty or non-string input');
  const t = text.trim();
  const errors: string[] = [];

  // Clean trailing commas (very common AI mistake)
  const cleanTrailing = (str: string) => str.replace(/,\s*([\}\]])/g, '$1');

  // Strip markdown blocks even if there is leading text
  const stripped = t.replace(/[\s\S]*?```(?:json)?\s*/i, '').replace(/\s*```[\s\S]*$/i, '').trim();

  const attempts = [
    stripped,
    cleanTrailing(stripped),
    t,
    cleanTrailing(t)
  ];

  // Bracket-counting safe extractor with auto-repair for truncated JSON
  const extractJson = (src: string): string | null => {
    for (let i = 0; i < src.length; i++) {
      const ch = src[i];
      if (ch !== '{' && ch !== '[') continue;
      const stack: string[] = [];
      let inStr = false;
      let escape = false;
      for (let j = i; j < src.length; j++) {
        const c = src[j];
        if (escape) { escape = false; continue; }
        if (c === '\\' && inStr) { escape = true; continue; }
        if (c === '"') { inStr = !inStr; continue; }
        if (inStr) continue;
        if (c === '{') stack.push('}');
        else if (c === '[') stack.push(']');
        else if (c === '}' || c === ']') {
          if (stack[stack.length - 1] === c) stack.pop();
          if (stack.length === 0) return src.slice(i, j + 1);
        }
      }

      // If we reach the end and stack is not empty, the JSON was truncated.
      // Repair it by closing any open strings and brackets.
      let repaired = src.slice(i);
      if (inStr) repaired += '"';
      while (stack.length > 0) {
        repaired += stack.pop();
      }
      return repaired;
    }
    return null;
  };

  const extracted = extractJson(t);
  if (extracted) {
    attempts.push(extracted);
    attempts.push(cleanTrailing(extracted));
  }

  for (const attempt of attempts) {
    if (!attempt) continue;
    try {
      return JSON.parse(attempt);
    } catch (e: any) {
      if (!errors.includes(e.message)) errors.push(e.message);
    }
  }

  console.error("AI JSON Parse Failed. Raw text:", text, "Errors:", errors);
  throw new Error(`Parse error: ${errors[0] || 'unknown'}. Raw: ${text.substring(0, 80)}...`);
};

/**
 * googleCalendar.ts ΓÇö Full bidirectional Google Calendar sync
 *
 * Uses Google Identity Services (GIS) OAuth + direct REST API calls.
 * Supports: create, update, delete, poll for external changes.
 *
 * REQUIRED SETUP:
 *   1. https://console.cloud.google.com ΓåÆ APIs & Services
 *   2. Enable "Google Calendar API"  ΓåÉ MUST DO THIS
 *   3. Credentials ΓåÆ OAuth 2.0 Client ID (Web Application)
 *      Authorized JS Origins: http://localhost:5173, https://myzentrack.vercel.app
 *   4. Set VITE_GOOGLE_CALENDAR_CLIENT_ID in .env
 */

const CLIENT_ID = import.meta.env.VITE_GOOGLE_CALENDAR_CLIENT_ID as string | undefined;
const SCOPES = 'https://www.googleapis.com/auth/calendar ' +
               'https://www.googleapis.com/auth/gmail.readonly ' +
               'https://www.googleapis.com/auth/gmail.send ' +
               'https://www.googleapis.com/auth/gmail.modify ' +
               'https://www.googleapis.com/auth/drive.file ' +
               'https://www.googleapis.com/auth/documents ' +
               'https://www.googleapis.com/auth/spreadsheets ' +
               'https://www.googleapis.com/auth/generative-language.retriever';
// NOTE: 'generative-language' (full) scope is NOT used here.
// Gemini generateContent API only accepts API Keys, NOT OAuth bearer tokens.
// Attempting to request this scope causes Error 400: invalid_scope unless the
// GCP project has explicit Generative Language API enrollment + consent screen approval.
const CALENDAR_API = 'https://www.googleapis.com/calendar/v3';

// ZenTrack source tag stored on GCal events to identify them
const ZENTRACK_SOURCE_TAG = 'zentrack-autosync';

// In-memory token state (initialized from localStorage)
let _accessToken: string | null = localStorage.getItem('zen_gcal_access_token');
let _tokenExpiry: number = parseInt(localStorage.getItem('zen_gcal_token_expiry') || '0', 10);
let _tokenClient: any = null;
let _gisLoaded = false;

// Sync state
let _syncToken: string | null = null;
let _lastSyncTime: number = 0;

// ΓöÇΓöÇΓöÇ Script Loader ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const loadGisScript = (): Promise<void> => {
  if (_gisLoaded) return Promise.resolve();
  const existing = document.getElementById('__gis_script__');
  if (existing) {
    return new Promise((resolve, reject) => {
      existing.addEventListener('load', () => { _gisLoaded = true; resolve(); });
      existing.addEventListener('error', reject);
    });
  }
  return new Promise((resolve, reject) => {
    const s = document.createElement('script');
    s.id = '__gis_script__';
    s.src = 'https://accounts.google.com/gsi/client';
    s.async = true;
    s.defer = true;
    s.onload = () => { _gisLoaded = true; resolve(); };
    s.onerror = reject;
    document.head.appendChild(s);
  });
};

// ΓöÇΓöÇΓöÇ Initialization ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export const initGoogleCalendar = async (): Promise<boolean> => {
  if (!CLIENT_ID) {
    console.warn('[GoogleCalendar] VITE_GOOGLE_CALENDAR_CLIENT_ID is not set.');
    return false;
  }
  try {
    await loadGisScript();
    return true;
  } catch (err) {
    console.error('[GoogleCalendar] Failed to load GIS script:', err);
    return false;
  }
};

// ΓöÇΓöÇΓöÇ Token State ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export const isSignedInToGoogle = (): boolean =>
  !!_accessToken && Date.now() < _tokenExpiry;

export const wasEverConnectedToGoogle = (): boolean =>
  !!localStorage.getItem('zen_gcal_access_token');

export const getTokenTimeRemaining = (): number =>
  _accessToken ? Math.max(0, _tokenExpiry - Date.now()) : 0;

let _refreshTimer: ReturnType<typeof setTimeout> | null = null;

const storeToken = (accessToken: string, expiresIn: number) => {
  _accessToken = accessToken;
  _tokenExpiry = Date.now() + Math.min(expiresIn * 1000, 55 * 60 * 1000);
  localStorage.setItem('zen_gcal_access_token', _accessToken);
  localStorage.setItem('zen_gcal_token_expiry', _tokenExpiry.toString());

  // Schedule a proactive silent refresh 5 minutes before expiry
  if (_refreshTimer) clearTimeout(_refreshTimer);
  const refreshIn = Math.max(0, _tokenExpiry - Date.now() - 5 * 60 * 1000);
  _refreshTimer = setTimeout(async () => {
    try {
      console.log('[GoogleCalendar] ≡ƒöä Proactive token refresh triggered...');
      await signInWithGoogle();
      console.log('[GoogleCalendar] Γ£à Token silently refreshed.');
      if (typeof window !== 'undefined') {
        window.dispatchEvent(new CustomEvent('google-token-refreshed'));
      }
    } catch (err) {
      console.warn('[GoogleCalendar] Silent refresh failed (user will be prompted on next action):', err);
    }
  }, refreshIn);
};

// ΓöÇΓöÇΓöÇ OAuth Sign-in ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export const signInWithGoogle = (): Promise<void> => {
  if (!CLIENT_ID) return Promise.reject(new Error('VITE_GOOGLE_CALENDAR_CLIENT_ID not set'));

  return new Promise((resolve, reject) => {
    // Add a 45-second timeout safeguard so the auth panel state does not hang indefinitely if the popup is blocked
    const timeoutId = setTimeout(() => {
      reject(new Error('Authentication timed out or the Google authorization popup was blocked.'));
    }, 45000);

    const doRequest = () => {
      try {
        _tokenClient = (window as any).google.accounts.oauth2.initTokenClient({
          client_id: CLIENT_ID,
          scope: SCOPES,
          callback: (response: any) => {
            clearTimeout(timeoutId);
            if (response.error) {
              reject(new Error(response.error_description || response.error));
              return;
            }
            storeToken(response.access_token, response.expires_in ?? 3600);
            console.log('[GoogleCalendar] Γ£à Token obtained');
            resolve();
          },
          error_callback: (err: any) => {
            clearTimeout(timeoutId);
            reject(new Error(err?.message || 'OAuth failed'));
          },
        });
        // Use prompt: 'select_account' so it reliably prompts user account chooser window
        _tokenClient.requestAccessToken({ prompt: 'select_account' });
      } catch (err: any) {
        clearTimeout(timeoutId);
        reject(new Error(err?.message || 'Failed to initialize Google Identity Services token client'));
      }
    };

    if (_gisLoaded && (window as any).google?.accounts?.oauth2) {
      doRequest();
    } else {
      loadGisScript()
        .then(doRequest)
        .catch((err) => {
          clearTimeout(timeoutId);
          reject(err);
        });
    }
  });
};

export const signOutGoogle = (): void => {
  if (_accessToken && (window as any).google?.accounts?.oauth2) {
    try { (window as any).google.accounts.oauth2.revoke(_accessToken, () => {}); } catch {}
  }
  _accessToken = null;
  _tokenExpiry = 0;
  _tokenClient = null;
  _syncToken = null;
  _lastSyncTime = 0;
  localStorage.removeItem('zen_gcal_access_token');
  localStorage.removeItem('zen_gcal_token_expiry');
};

// ΓöÇΓöÇΓöÇ Token Refresh ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

let _tokenRefreshPromise: Promise<string> | null = null;

export const ensureToken = async (): Promise<string> => {
  const BUFFER_MS = 5 * 60 * 1000; // 5 minutes
  const isFresh = !!_accessToken && Date.now() < (_tokenExpiry - BUFFER_MS);
  if (isFresh && _accessToken) return _accessToken;

  if (_tokenRefreshPromise) {
    return _tokenRefreshPromise;
  }

  _tokenRefreshPromise = (async () => {
    try {
      await signInWithGoogle();
      if (!_accessToken) throw new Error('Could not obtain Google access token');
      return _accessToken;
    } finally {
      _tokenRefreshPromise = null;
    }
  })();

  return _tokenRefreshPromise;
};

// ΓöÇΓöÇΓöÇ REST API Helper ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const calendarFetch = async <T>(
  path: string,
  method: 'GET' | 'POST' | 'PATCH' | 'PUT' | 'DELETE' = 'GET',
  body?: object,
  signal?: AbortSignal
): Promise<T> => {
  const token = await ensureToken();

  const res = await fetch(`${CALENDAR_API}${path}`, {
    method,
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
    body: body ? JSON.stringify(body) : undefined,
    signal,
  });

  if (!res.ok) {
    if (res.status === 429) {
      const retryAfter = parseInt(res.headers.get('Retry-After') || '60', 10);
      throw new Error(`429 Rate Limited: retry after ${retryAfter}s`);
    }

    let errorMsg = `HTTP ${res.status}`;
    try {
      const errData = await res.json();
      errorMsg = errData?.error?.message || errorMsg;
      // Surface the API-not-enabled URL for easy fixing
      if (errData?.error?.errors?.[0]?.reason === 'accessNotConfigured') {
        const detailsUrl = errData.error.errors[0]?.extendedHelp || '';
        throw new Error(`Google Calendar API is not enabled. Enable it at: ${detailsUrl || 'https://console.cloud.google.com/apis/library/calendar-json.googleapis.com'}`);
      }
    } catch (e: any) {
      if (e.message.includes('not enabled') || e.message.includes('Enable it')) throw e;
    }
    throw new Error(`Google Calendar API error: ${errorMsg}`);
  }

  if (method === 'DELETE') return undefined as T;
  return res.json() as Promise<T>;
};

// ΓöÇΓöÇΓöÇ Types ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export interface GCalEvent {
  title: string;
  date: string;        // YYYY-MM-DD
  startDateTime?: string; // ISO String
  endDateTime?: string;   // ISO String
  description?: string;
  location?: string;
  attendees?: string[];
  type?: string;
  zentrackId?: string; // Firestore document ID ΓÇö stored in GCal for dedup
}

export interface GCalListEvent {
  id: string;
  summary: string;
  description?: string;
  status?: string;     // 'cancelled' for deleted events
  start: { date?: string; dateTime?: string };
  end: { date?: string; dateTime?: string };
  htmlLink: string;
  extendedProperties?: {
    private?: { source?: string; zentrackId?: string; type?: string };
  };
}

// ΓöÇΓöÇΓöÇ Date Helper ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const nextDay = (date: string): string => {
  const [y, m, d] = date.split('-').map(Number);
  const next = new Date(y, m - 1, d + 1);
  return `${next.getFullYear()}-${String(next.getMonth() + 1).padStart(2, '0')}-${String(next.getDate()).padStart(2, '0')}`;
};

const buildCalEventBody = (event: GCalEvent) => ({
  summary: event.title,
  description: event.description ?? `ZenTrack ΓÇö ${event.type || 'Event'}`,
  location: event.location,
  attendees: event.attendees?.map(email => ({ email })),
  start: event.startDateTime ? { dateTime: event.startDateTime } : { date: event.date },
  end: event.endDateTime ? { dateTime: event.endDateTime } : { date: nextDay(event.date) },
  extendedProperties: {
    private: {
      source: ZENTRACK_SOURCE_TAG,
      zentrackId: event.zentrackId ?? '',
      type: event.type || 'auto-scheduled',
    },
  },
  reminders: {
    useDefault: false,
    overrides: [
      { method: 'popup', minutes: 24 * 60 },
      { method: 'popup', minutes: 60 },
    ],
  },
});

// ΓöÇΓöÇΓöÇ CREATE ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** Creates event in Google Calendar and returns the GCal event ID */
export const addEventToGoogleCalendar = async (event: GCalEvent, signal?: AbortSignal): Promise<string> => {
  const result = await calendarFetch<any>(
    '/calendars/primary/events',
    'POST',
    buildCalEventBody(event),
    signal
  );
  console.log('[GoogleCalendar] Γ£à Created:', result?.summary, result?.id);
  return result.id as string;
};

// ΓöÇΓöÇΓöÇ UPDATE ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** Updates an existing GCal event by its GCal event ID */
export const updateGoogleCalendarEvent = async (gcalEventId: string, event: GCalEvent, signal?: AbortSignal): Promise<void> => {
  await calendarFetch<any>(
    `/calendars/primary/events/${gcalEventId}`,
    'PUT',
    buildCalEventBody(event),
    signal
  );
  console.log('[GoogleCalendar] Γ£à Updated:', event.title);
};

// ΓöÇΓöÇΓöÇ DELETE ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** Deletes a GCal event by its GCal event ID */
export const deleteGoogleCalendarEvent = async (gcalEventId: string, signal?: AbortSignal): Promise<void> => {
  await calendarFetch<void>(`/calendars/primary/events/${gcalEventId}`, 'DELETE', undefined, signal);
  console.log('[GoogleCalendar] Γ£à Deleted gcalId:', gcalEventId);
};

// ΓöÇΓöÇΓöÇ POLL FOR CHANGES ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export interface GCalChangesResult {
  added: GCalListEvent[];      // New events added externally (not from ZenTrack)
  deleted: string[];           // GCal IDs of deleted events
  nextSyncToken: string | null;
}

/**
 * Polls Google Calendar for changes since last sync.
 * First call does a full initial sync; subsequent calls use syncToken.
 */
export const pollGoogleCalendarChanges = async (signal?: AbortSignal): Promise<GCalChangesResult> => {
  let url: string;

  if (_syncToken) {
    // Incremental sync using the syncToken from last poll
    url = `/calendars/primary/events?syncToken=${encodeURIComponent(_syncToken)}&singleEvents=true`;
  } else {
    // Initial full sync ΓÇö fetch events from 90 days ago to 180 days ahead
    const timeMin = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000).toISOString();
    const timeMax = new Date(Date.now() + 180 * 24 * 60 * 60 * 1000).toISOString();
    url = `/calendars/primary/events?timeMin=${encodeURIComponent(timeMin)}&timeMax=${encodeURIComponent(timeMax)}&singleEvents=true&maxResults=250`;
  }

  const data = await calendarFetch<{
    items?: GCalListEvent[];
    nextSyncToken?: string;
    nextPageToken?: string;
  }>(url, 'GET', undefined, signal);

  _syncToken = data.nextSyncToken ?? null;
  _lastSyncTime = Date.now();

  const items = data.items ?? [];
  const added: GCalListEvent[] = [];
  const deleted: string[] = [];

  for (const item of items) {
    if (item.status === 'cancelled') {
      deleted.push(item.id);
      continue;
    }
    // Skip events we created from ZenTrack (identified by extendedProperties)
    const isFromZentrack = item.extendedProperties?.private?.source === ZENTRACK_SOURCE_TAG;
    if (!isFromZentrack) {
      added.push(item);
    }
  }

  return { added, deleted, nextSyncToken: _syncToken };
};

