export type LogType = 'API' | 'WEBSOCKET';

export interface NetworkLog {
  id: string;
  type: LogType;
  method?: 'GET' | 'POST' | 'PATCH' | 'DELETE';
  endpoint?: string;
  event?: string;
  payload: unknown;
  status: 'pending' | 'success' | 'error';
  timestamp: number;
}

export const logApi = (method: 'GET' | 'POST' | 'PATCH' | 'DELETE', endpoint: string, payload: unknown = {}, status: 'pending' | 'success' | 'error' = 'success') => {
  const log: NetworkLog = {
    id: Math.random().toString(36).substring(2, 9),
    type: 'API',
    method,
    endpoint,
    payload,
    status,
    timestamp: Date.now()
  };
  window.dispatchEvent(new CustomEvent('network-log', { detail: log }));
};

export const logWebSocket = (event: string, payload: any = {}) => {
  const log: NetworkLog = {
    id: Math.random().toString(36).substring(2, 9),
    type: 'WEBSOCKET',
    event,
    payload,
    status: 'success',
    timestamp: Date.now()
  };
  window.dispatchEvent(new CustomEvent('network-log', { detail: log }));
};

let audioCtx: AudioContext | null = null;

export const playPopSound = () => {
  try {
    if (!audioCtx) {
      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContextClass) return;
      audioCtx = new AudioContextClass();
    }

    // Resume context if suspended (browser autoplay policy)
    if (audioCtx.state === 'suspended') {
      audioCtx.resume();
    }

    const osc = audioCtx.createOscillator();
    const gainNode = audioCtx.createGain();

    osc.type = 'sine';

    // Quick pop frequency sweep
    osc.frequency.setValueAtTime(800, audioCtx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(300, audioCtx.currentTime + 0.1);

    // Quick volume envelope
    gainNode.gain.setValueAtTime(0, audioCtx.currentTime);
    gainNode.gain.linearRampToValueAtTime(0.5, audioCtx.currentTime + 0.01);
    gainNode.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.1);

    osc.connect(gainNode);
    gainNode.connect(audioCtx.destination);

    osc.start();
    osc.stop(audioCtx.currentTime + 0.1);
  } catch (e) {
    console.error('Audio context error:', e);
  }
};
